<?php require __DIR__."/vendor/autoload.php"; $app = require_once __DIR__."/bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Http\Kernel::class); $request = Illuminate\Http\Request::create("/api/profile/avatar", "POST", [], [], ["avatar" => new Illuminate\Http\UploadedFile(__DIR__."/test.jpg", "test.jpg", "image/jpeg", null, true)]); $response = $kernel->handle($request); echo $response->getContent();